import React from 'react';
import { motion } from 'framer-motion';

const EsteemedClients = () => {
  // Client logos with unique animations (NO flip cards)
  const clients = [
    {
      name: 'Indian institute of banking and finance',
      logo: 'data:image/png;base64,',
      animation: 'pulse'
    },
    {
      name: 'DDecor exports',
      logo: 'data:image/jpeg;base64,',
      animation: 'bounce'
    },
    {
      name: 'Fine organics',
      logo: 'data:image/png;base64,',
      animation: 'glow'
    },
    {
      name: 'Fine Zeelandia',
      logo: 'data:image/jpeg;base64,',
      animation: 'scale'
    },
    {
      name: 'Bhabha Atomic Research Centre',
      logo: 'data:image/jpeg;base64,',
      animation: 'rotate'
    },
    {
      name: 'ArcelorMittal Nippon Steel India',
      logo: 'data:image/png;base64,',
      animation: 'slide'
    },
    {
      name: 'Pianopresitel',
      logo: 'data:image/jpeg;base64,',
      animation: 'wave'
    },
    {
      name: 'DDecor Home',
      logo: 'data:image/png;base64,',
      animation: 'shake'
    }
  ];

  const getAnimation = (type) => {
    switch (type) {
      case 'pulse':
        return {
          animate: { scale: [1, 1.05, 1] },
          transition: { duration: 2, repeat: Infinity }
        };
      case 'bounce':
        return {
          animate: { y: [0, -8, 0] },
          transition: { duration: 1.5, repeat: Infinity }
        };
      case 'glow':
        return {
          animate: { 
            boxShadow: [
              '0 0 20px rgba(0,74,173,0.2)',
              '0 0 40px rgba(0,74,173,0.5)',
              '0 0 20px rgba(0,74,173,0.2)'
            ]
          },
          transition: { duration: 2, repeat: Infinity }
        };
      case 'scale':
        return {
          animate: { scale: [1, 1.08, 1] },
          transition: { duration: 2.5, repeat: Infinity }
        };
      case 'rotate':
        return {
          animate: { rotate: [0, 3, -3, 0] },
          transition: { duration: 3, repeat: Infinity }
        };
      case 'slide':
        return {
          animate: { x: [0, 5, -5, 0] },
          transition: { duration: 2, repeat: Infinity }
        };
      case 'wave':
        return {
          animate: { y: [0, -5, 0, 5, 0] },
          transition: { duration: 2, repeat: Infinity }
        };
      case 'shake':
        return {
          animate: { x: [0, 2, -2, 2, 0] },
          transition: { duration: 0.5, repeat: Infinity, repeatDelay: 2 }
        };
      default:
        return {
          animate: {},
          transition: {}
        };
    }
  };

  return (
    <section className="relative py-16 sm:py-20 bg-gradient-to-b from-[#e8f0ff] via-[#bed3ff]/30 to-[#f8faff] overflow-hidden">
      {/* Background Elements */}
      <div className="absolute inset-0 opacity-30">
        <motion.div
          animate={{ rotate: 360 }}
          transition={{ duration: 60, repeat: Infinity, ease: "linear" }}
          className="absolute -top-40 -right-40 w-80 h-80 border border-[#004aad]/20 rounded-full"
        />
        <motion.div
          animate={{ rotate: -360 }}
          transition={{ duration: 80, repeat: Infinity, ease: "linear" }}
          className="absolute -bottom-60 -left-60 w-96 h-96 border border-[#004aad]/10 rounded-full"
        />
      </div>

      <div className="max-w-[1600px] mx-auto px-4 sm:px-8 lg:px-16 relative z-10">
        {/* Section Header */}
        <motion.div
          initial={{ opacity: 0, y: 30 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          className="text-center mb-10 sm:mb-12"
        >
          <motion.div
            initial={{ opacity: 0, scale: 0.9 }}
            whileInView={{ opacity: 1, scale: 1 }}
            viewport={{ once: true }}
            className="inline-block mb-4"
          >
            <span className="px-5 py-2 bg-gradient-to-r from-[#004aad]/10 to-[#bed3ff]/20 text-[#004aad] rounded-full text-xs sm:text-sm font-bold uppercase tracking-wider border border-[#004aad]/20">
              Trusted Partners
            </span>
          </motion.div>
          <h2 className="text-3xl sm:text-4xl lg:text-5xl font-bold text-[#1a1a2e] mb-4">
            Our Esteemed{' '}
            <span className="bg-gradient-to-r from-[#004aad] to-[#0066cc] bg-clip-text text-transparent">
              Clients
            </span>
          </h2>
          <p className="text-base sm:text-lg text-[#4a5568] max-w-3xl mx-auto">
            Powering digital transformation for industry leaders across the globe
          </p>
        </motion.div>

        {/* Clients Grid with Unique Animations */}
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 sm:gap-6 mb-10 sm:mb-12">
          {clients.map((client, index) => {
            const animation = getAnimation(client.animation);
            return (
              <motion.div
                key={index}
                initial={{ opacity: 0, y: 20 }}
                whileInView={{ opacity: 1, y: 0 }}
                viewport={{ once: true }}
                transition={{ delay: index * 0.1 }}
                className="group"
              >
                <motion.div
                  {...animation}
                  whileHover={{ scale: 1.1, y: -10 }}
                  className="bg-white/80 backdrop-blur-sm rounded-2xl p-8 shadow-lg border border-[#bed3ff]/30 hover:border-[#004aad]/50 transition-all duration-300 hover:shadow-2xl
           h-[260px] flex flex-col justify-between"

                >
                  <div className="h-[120px] w-full flex items-center justify-center rounded-lg bg-white">
  <img
    src={client.logo}
    alt={client.name}
    className="max-h-[90px] max-w-[85%] object-contain opacity-70 
               group-hover:opacity-100 transition-all duration-300 
               grayscale group-hover:grayscale-0"
  />
</div>

                  <p className="text-center mt-4 text-[#1a1a2e] font-semibold text-lg opacity-0 group-hover:opacity-100 transition-opacity duration-300">
                    {client.name}
                  </p>
                </motion.div>
              </motion.div>
            );
          })}
        </div>

        {/* Trust Stats */}
        <motion.div
          initial={{ opacity: 0, y: 30 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          className="grid grid-cols-2 md:grid-cols-4 gap-8 bg-gradient-to-br from-white/90 to-[#f0f5ff]/90 backdrop-blur-sm rounded-3xl p-10 shadow-xl border border-[#004aad]/10"
        >
          {[
            { value: '250+', label: 'Enterprise Clients', icon: '🏢' },
            { value: '45+', label: 'Countries Served', icon: '🌍' },
            { value: '$2B+', label: 'Assets Protected', icon: '🛡️' },
            { value: '15+', label: 'Years Experience', icon: '⭐' }
          ].map((stat, index) => (
            <motion.div
              key={index}
              initial={{ opacity: 0, scale: 0.8 }}
              whileInView={{ opacity: 1, scale: 1 }}
              viewport={{ once: true }}
              transition={{ delay: 0.3 + index * 0.1 }}
              whileHover={{ y: -5 }}
              className="text-center"
            >
              <motion.div
                animate={{ scale: [1, 1.1, 1] }}
                transition={{ duration: 2, repeat: Infinity, delay: index * 0.3 }}
                className="text-4xl mb-3"
              >
                {stat.icon}
              </motion.div>
              <div className="text-4xl lg:text-5xl font-bold bg-gradient-to-r from-[#004aad] to-[#0066cc] bg-clip-text text-transparent mb-2">
                {stat.value}
              </div>
              <div className="text-[#4a5568] font-medium">
                {stat.label}
              </div>
            </motion.div>
          ))}
        </motion.div>
      </div>
    </section>
  );
};

export default EsteemedClients;
